chart-tokens-by-model.query:
timeseries tokens = sum(`gen_ai.client.token.usage`), by: {`gen_ai.request.model`}, filter: {`gen_ai.system` == "google_gemini"}
| summarize totalTokens = sum(arraySum(tokens)), by: {`gen_ai.request.model`}
| sort totalTokens desc

chart-duration-by-model.query:
timeseries dur = avg(`gen_ai.client.operation.duration`), by: {`gen_ai.request.model`}, filter: {`gen_ai.system` == "google_gemini"}
| summarize avgDur = sum(arrayAvg(dur)), by: {`gen_ai.request.model`}
| sort avgDur desc

table-token-breakdown.query:
timeseries tokens = sum(`gen_ai.client.token.usage`), by: {`gen_ai.request.model`, `gen_ai.token.type`}, filter: {`gen_ai.system` == "google_gemini"}
| summarize totalTokens = sum(arraySum(tokens)), by: {`gen_ai.request.model`, `gen_ai.token.type`}
| sort totalTokens desc

chart-tokens-by-user.query:
timeseries tokens = sum(`gen_ai.client.token.usage`), by: {`user.email`}, filter: {`gen_ai.system` == "google_gemini"}
| summarize totalTokens = sum(arraySum(tokens)), by: {`user.email`}
| sort totalTokens desc

chart-event-volume-by-type.query:
fetch logs
| filter service.name == "gemini-cli"
| makeTimeseries count = count(), by: {`event.name`}
